    "points": [
      {
        "title": "Chills",
        "content": "Indicates the body is trying to raise its temperature.",
        "icon": "chill_icon.png"
      },
      {
        "title": "Fever",
        "content": "Body temperature above normal range, often a sign of infection.",
        "icon": "fever_icon.png"
      },
      {
        "title": "Sweating",
        "content": "Occurs as the body attempts to cool down.",
        "icon": "sweat_icon.png"
      },
      {
        "title": "Fatigue",
        "content": "Common symptom during cold or fever, indicating the body is fighting an illness.",
        "icon": "fatigue_icon.png"
      }
    ]
  }
